import React, { useState } from "react";
import { ethers } from "ethers";
// Ensure these paths match your folder structure (Step 6 in README)
import CrowdfundingABI from "../utils/abi/Crowdfunding.json";
import addresses from "../utils/addresses.json";

export default function Refund() {
  const [campaignId, setCampaignId] = useState("");
  const [loading, setLoading] = useState(false);
  const [message, setMessage] = useState("");

  const handleRefund = async (e) => {
    e.preventDefault();
    setMessage("");

    if (!window.ethereum) {
      setMessage("❌ Please install MetaMask!");
      return;
    }

    try {
      setLoading(true);
      
      // 1. Connect to MetaMask
      const provider = new ethers.BrowserProvider(window.ethereum);
      const signer = await provider.getSigner();

      // 2. Connect to the deployed contract
      const contract = new ethers.Contract(
        addresses.Crowdfunding, 
        CrowdfundingABI.abi, 
        signer
      );

      // 3. Call the claimRefund function
      const tx = await contract.claimRefund(campaignId);
      setMessage("⏳ Processing refund... please wait.");
      
      // 4. Wait for the transaction to be mined
      await tx.wait();
      setMessage(`✅ Refund successful for Campaign #${campaignId}!`);
      setCampaignId("");

    } catch (error) {
      console.error(error);
      // Clean up the error message from MetaMask/Hardhat
      const errorMsg = error.reason || error.message || "An error occurred";
      setMessage(`❌ Failed: ${errorMsg}`);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={{ padding: "20px", maxWidth: "500px", margin: "0 auto" }}>
      <h2>Claim Your Refund 💸</h2>
      <p>If a campaign failed to reach its goal by the deadline, you can claim your ETH back here.</p>
      
      <form onSubmit={handleRefund} style={{ display: "flex", flexDirection: "column", gap: "10px" }}>
        <input
          type="number"
          placeholder="Enter Campaign ID"
          value={campaignId}
          onChange={(e) => setCampaignId(e.target.value)}
          required
          style={{ padding: "10px", fontSize: "16px" }}
        />
        
        <button 
          type="submit" 
          disabled={loading || !campaignId}
          style={{ 
            padding: "10px", 
            fontSize: "16px", 
            backgroundColor: loading ? "#ccc" : "#ff4d4f",
            color: "white",
            border: "none",
            cursor: loading ? "not-allowed" : "pointer"
          }}
        >
          {loading ? "Processing..." : "Claim Refund"}
        </button>
      </form>

      {message && (
        <div style={{ marginTop: "20px", padding: "10px", backgroundColor: "#f0f0f0", borderRadius: "5px" }}>
          <strong>{message}</strong>
        </div>
      )}
    </div>
  );
}
